function changeSubscription(userId, currentPlan, newPlan) {
  let chargeAmount = 0;
  if (newPlan === 'free') {
    chargeAmount = 0;
  } else if (newPlan === 'pro') {
    chargeAmount = 10;
  } else if (newPlan === 'enterprise') {
    chargeAmount = 50;
  }

  const difference = chargeAmount - currentPlan.price;

  return {
    newPlan,
    chargeAmount,
    difference,
  };
}